/* htmx 1.9 — vendored minimal implementation for event-spec admin UI */
(function(){
"use strict";
var htmx = {version:"1.9.x-vendored"};

function parseInterval(str){
  if(!str)return null;
  if(str.endsWith("ms"))return parseInt(str);
  if(str.endsWith("s"))return parseFloat(str)*1000;
  return parseInt(str);
}

function closest(el, sel){
  while(el){if(el.matches && el.matches(sel))return el; el=el.parentElement;}
  return null;
}

function getTarget(el, spec){
  if(!spec||spec==="this")return el;
  if(spec==="closest")return el.parentElement;
  if(spec.startsWith("closest "))return closest(el,spec.slice(8));
  if(spec==="next")return el.nextElementSibling;
  if(spec==="previous")return el.previousElementSibling;
  return document.querySelector(spec);
}

function swap(target, html, swapSpec){
  if(!target)return;
  swapSpec = swapSpec||"innerHTML";
  if(swapSpec==="outerHTML")target.outerHTML=html;
  else if(swapSpec==="innerHTML")target.innerHTML=html;
  else if(swapSpec==="afterend")target.insertAdjacentHTML("afterend",html);
  else if(swapSpec==="beforebegin")target.insertAdjacentHTML("beforebegin",html);
  else if(swapSpec==="afterbegin")target.insertAdjacentHTML("afterbegin",html);
  else if(swapSpec==="beforeend")target.insertAdjacentHTML("beforeend",html);
  else if(swapSpec==="delete")target.remove();
  else if(swapSpec==="none"){}
  else target.innerHTML=html;
}

function buildFormData(el){
  var form=closest(el,"form");
  var fd=new FormData(form||undefined);
  var vals=el.getAttribute("hx-vals");
  if(vals){
    try{var obj=JSON.parse(vals);for(var k in obj)fd.set(k,obj[k]);}catch(e){}
  }
  return fd;
}

function doRequest(el, method, url){
  var target=getTarget(el, el.getAttribute("hx-target"));
  var swapSpec=el.getAttribute("hx-swap")||"innerHTML";
  var confirm=el.getAttribute("hx-confirm");
  if(confirm&&!window.confirm(confirm))return;

  var opts={method:method.toUpperCase(),headers:{"HX-Request":"true"}};
  if(method!=="GET"&&method!=="DELETE"){
    var fd=buildFormData(el);
    var vals=el.getAttribute("hx-vals");
    if(vals){
      try{opts.headers["Content-Type"]="application/json"; opts.body=vals;}
      catch(e){}
    } else {
      opts.body=fd;
    }
  } else if(method==="DELETE"){
    var vals2=el.getAttribute("hx-vals");
    if(vals2){opts.headers["Content-Type"]="application/json";opts.body=vals2;}
  }

  fetch(url,opts).then(function(r){
    if(!r.ok&&swapSpec!=="none")return;
    return r.text();
  }).then(function(html){
    if(html!==undefined) swap(target,html,swapSpec);
    // trigger hx-on:htmx:afterSwap if needed
  }).catch(function(){});
}

function processEl(el){
  var attrs=["hx-get","hx-post","hx-put","hx-patch","hx-delete"];
  var methods=["get","post","put","patch","delete"];
  for(var i=0;i<attrs.length;i++){
    var url=el.getAttribute(attrs[i]);
    if(!url)continue;
    var method=methods[i];
    var trigger=el.getAttribute("hx-trigger");
    if(!trigger){
      if(el.tagName==="FORM")trigger="submit";
      else if(el.tagName==="INPUT"||el.tagName==="SELECT"||el.tagName==="TEXTAREA")trigger="change";
      else trigger="click";
    }
    (function(el,method,url,trigger){
      el.addEventListener(trigger,function(e){
        e.preventDefault();
        doRequest(el,method,url);
      });
    })(el,method,url,trigger);
  }
}

function processAll(root){
  var attrs=["hx-get","hx-post","hx-put","hx-patch","hx-delete"];
  attrs.forEach(function(attr){
    root.querySelectorAll("["+attr+"]").forEach(processEl);
  });
}

document.addEventListener("DOMContentLoaded",function(){processAll(document);});

// Process dynamically added nodes
var observer=new MutationObserver(function(muts){
  muts.forEach(function(m){
    m.addedNodes.forEach(function(n){
      if(n.nodeType===1){processEl(n);processAll(n);}
    });
  });
});
observer.observe(document.body,{childList:true,subtree:true});

window.htmx=htmx;
})();
